# billing/sla_measurement.py
# Compute the monthly availability for SLA reporting.
# Excludes scheduled maintenance and customer-caused failures.
from dataclasses import dataclass
from datetime import datetime, timedelta
from typing import List

@dataclass
class MaintenanceWindow:
    start: datetime
    end: datetime
    announced_at: datetime  # must be >= 72h before start

    @property
    def valid(self) -> bool:
        return (self.start - self.announced_at) >= timedelta(hours=72)

@dataclass
class AvailabilityMeasurement:
    total_minutes: int
    downtime_minutes: float
    maintenance_excluded_minutes: float
    customer_error_excluded_minutes: float

    @property
    def eligible_minutes(self) -> float:
        return (self.total_minutes
                - self.maintenance_excluded_minutes
                - self.customer_error_excluded_minutes)

    @property
    def availability(self) -> float:
        if self.eligible_minutes == 0:
            return 1.0
        uptime = self.eligible_minutes - self.downtime_minutes
        return max(0.0, uptime / self.eligible_minutes)

def compute_monthly_availability(
    downtime_minutes: float,
    maintenance_windows: List[MaintenanceWindow],
    customer_error_minutes: float = 0,
) -> AvailabilityMeasurement:
    month_minutes = 30 * 24 * 60  # 43200
    maint_excluded = sum(
        (w.end - w.start).total_seconds() / 60
        for w in maintenance_windows if w.valid
    )
    return AvailabilityMeasurement(
        total_minutes=month_minutes,
        downtime_minutes=downtime_minutes,
        maintenance_excluded_minutes=maint_excluded,
        customer_error_excluded_minutes=customer_error_minutes,
    )
